// 1. Intentamos recuperar la lista de tablas del nodo de origen
let tables = "";

try {
  tables = $('Extract Table Names').first().json.tablesList;
} catch (e) {
  // Si n8n no encuentra el nodo por ejecuciones parciales, buscamos en el historial
  const items = $('Extract Table Names').all();
  if (items.length > 0) {
    tables = items[0].json.tablesList;
  }
}

// 2. ¡EL SALVAVIDAS CRÍTICO!
// Si 'tables' llega undefined, vacío o no tiene texto, le inyectamos a la fuerza
// tus tablas reales entre comillas simples para que Postgres no lance el error de sintaxis.
if (!tables || tables.trim() === "" || tables === "()") {
  tables = "'facturas', 'ventas'"; 
}

// 3. Construimos la consulta limpia asignándola a la propiedad "sql"
const queryFinal = `SELECT table_schema, table_name, column_name, data_type FROM information_schema.columns WHERE table_schema = 'public' AND table_name IN (${tables}) ORDER BY table_name, ordinal_position;`;

return [{
  json: {
    sql: queryFinal
  }
}];

let dirtyText = "";
if ($json.content && $json.content.parts && $json.content.parts[0]) {
    dirtyText = $json.content.parts[0].text;
} else {
    dirtyText = $json.text || $json.output || $json.message?.content || "";
}
if (!dirtyText || dirtyText.trim() === "") {
    return { error: "El texto de la IA llegó vacío.", raw: "VACÍO" };
}
const start = dirtyText.indexOf('{');
const end = dirtyText.lastIndexOf('}');
if (start !== -1 && end !== -1) {
    const cleanJsonString = dirtyText.substring(start, end + 1);
    try {
        return JSON.parse(cleanJsonString);
    } catch (e) {
        return { error: "JSON mal formado", raw: dirtyText };
    }
}
return { error: "No se encontró el símbolo '{' en la respuesta", raw: dirtyText };

let dirtyText = $json.output || $json.text || "";
const start = dirtyText.indexOf('{');
const end = dirtyText.lastIndexOf('}');
let parsed = {};
if (start !== -1 && end !== -1) {
    try {
        parsed = JSON.parse(dirtyText.substring(start, end + 1));
    } catch (e) {
        let sqlMatch = dirtyText.match(/"sql"\s*:\s*"([^"]+)"/);
        let templateMatch = dirtyText.match(/"template"\s*:\s*"([^"]+)"/);
        parsed.sql = sqlMatch ? sqlMatch[1] : dirtyText;
        parsed.template = templateMatch ? templateMatch[1] : "Aquí tienes los datos: " + "{" + "{DATOS}" + "}";
    }
} else {
    parsed.sql = dirtyText;
    parsed.template = "Aquí tienes los datos: " + "{" + "{DATOS}" + "}";
}

let sql = parsed.sql || "";
sql = sql.replace(/```sql|```/gi, '').trim();
const selectIndex = sql.toUpperCase().indexOf("SELECT");
if (selectIndex !== -1) {
    sql = sql.substring(selectIndex);
}
sql = sql.replace(/\s+/g, ' ').trim();

return {
    json: {
        sql: sql,
        template: parsed.template || "Aquí tienes los datos: " + "{" + "{DATOS}" + "}"
    }
};

// 1. Capturamos el string en bruto que viene del agente
const rawOutput = $('Agente de Seguridad y Validación').first().json.output;

if (!rawOutput) {
  throw new Error("El nodo anterior no entregó la propiedad 'output'.");
}

// 2. Parseamos el string de texto para convertirlo en un objeto JSON real de JavaScript
const parsedJSON = JSON.parse(rawOutput);

// 3. Extraemos las variables ya limpias y procesadas
const sqlQuery = parsedJSON.sql;
const template = parsedJSON.template;
const reasoning = parsedJSON.reasoning;

// 4. Validación de seguridad final en el código
if (!sqlQuery || !sqlQuery.toUpperCase().trim().startsWith("SELECT")) {
  throw new Error("Violación de Seguridad: La consulta generada no es un SELECT válido.");
}

// 5. Devolvemos los datos estructurados a los canales nativos de n8n
return [{
  json: {
    reasoning: reasoning,
    sql: sqlQuery,
    template: template
  }
}];

const items = $input.all();
const tables = items.map(item => item.json.metadata?.table || item.json.table).filter(Boolean);
const sqlInList = tables.map(t => `'${t}'`).join(', ');
return { json: { tablesList: sqlInList, rawTables: tables } };

const body = $input.item.json.body || {};
const conn = body.connection_string || '';
let engine = 'postgres';
if (conn.startsWith('mysql')) engine = 'mysql';
else if (conn.startsWith('oracle')) engine = 'oracle';
else if (conn.startsWith('sqlserver')) engine = 'mssql';
return { json: { ...body, engine } };

// 1. Extraemos el SQL que viene del paso anterior
const sqlQuery = $('Parser Agente 2').first().json.sql;
const template = $('Parser Agente 2').first().json.template;
const reasoning = $('Parser Agente 2').first().json.reasoning;

if (!sqlQuery) {
  throw new Error("Violación de Seguridad: No se detectó ninguna consulta SQL.");
}

// 2. Forzamos la regla de oro: Solo consultas SELECT por seguridad Zero-Trust
const cleanQuery = sqlQuery.trim().toUpperCase();
if (!cleanQuery.startsWith("SELECT")) {
  throw new Error("Violación de Seguridad: Únicamente se permiten consultas estructuradas de tipo SELECT.");
}

// 3. Si pasa las auditorías, devolvemos los datos limpios para el backend
return [{
  json: {
    reasoning: reasoning,
    sql: sqlQuery,
    template: template
  }
}];
